# Per-minute joint state — score margin + smoothed home_prob
# Mirrors v4_phase2_polson_stern.build_per_minute_state.
# ---------------------------------------------------------------------------


_CLOCK_RE = re.compile(r"PT(?:(\d+)M)?(?:([\d.]+)S)?")


def parse_elapsed_min(period: object, clock: object) -> float:
    """Elapsed game-clock minute (0 at tipoff) for one PBP event."""
    if period is None or clock is None:
        return float("nan")
    if isinstance(period, float) and np.isnan(period):
        return float("nan")
    try:
        p = int(period)  # type: ignore[call-overload]
    except (TypeError, ValueError):
        return float("nan")
    m = _CLOCK_RE.match(str(clock))
    if not m:
        return float("nan")
    mins = float(m.group(1) or 0)
    secs = float(m.group(2) or 0)
    clock_min = mins + secs / 60.0
    if p <= 4:
        return float((p - 1) * PERIOD_MIN + (PERIOD_MIN - clock_min))
    return float(4 * PERIOD_MIN + (p - 5) * OT_MIN + (OT_MIN - clock_min))


def build_per_minute_state(
    *, smoothed_g: pd.DataFrame, pbp_g: pd.DataFrame,
) -> pd.DataFrame:
    """Per-game-clock-minute series joining smoothed market price with
    score margin. Right-edge causal (each minute uses only data <= that minute).
    """
    if smoothed_g.empty or pbp_g.empty:
        return pd.DataFrame()

    smoothed_g = smoothed_g.copy()
    smoothed_g["time_actual"] = pd.to_datetime(
        smoothed_g["time_actual"], utc=True,
    )
    smoothed_g = smoothed_g.dropna(subset=["home_prob_smooth"])
    if smoothed_g.empty:
        return pd.DataFrame()

    pbp_g = pbp_g.copy()
    pbp_g["time_actual"] = pd.to_datetime(pbp_g["time_actual"], utc=True)

    pbp_g["elapsed_min"] = pbp_g.apply(
        lambda r: parse_elapsed_min(r["period"], r["clock"]),
        axis=1,
    )
    pbp_g = pbp_g.dropna(subset=["elapsed_min"]).copy()
    if pbp_g.empty:
        return pd.DataFrame()
    pbp_g = pbp_g.sort_values(["elapsed_min", "time_actual"]).reset_index(drop=True)

    max_elapsed = float(pbp_g["elapsed_min"].max())
    n_minutes = int(np.floor(max_elapsed)) + 1
    if n_minutes <= 0:
        return pd.DataFrame()

    minute_idx = np.arange(n_minutes, dtype=int)
    elapsed_arr = pbp_g["elapsed_min"].to_numpy(dtype=float)
    insert_pos = np.searchsorted(elapsed_arr, minute_idx + 1e-9, side="right") - 1
    valid = insert_pos >= 0
    pbp_idx = np.where(valid, insert_pos, 0)

    selected = pbp_g.iloc[pbp_idx].reset_index(drop=True)
    grid = pd.DataFrame({
        "minute": minute_idx,
        "time_minute": selected["time_actual"].to_numpy(),
        "score_home": selected["score_home"].to_numpy(),
        "score_away": selected["score_away"].to_numpy(),
        "period": selected["period"].to_numpy(),
    })
    if not valid.all():
        bad = ~valid
        grid.loc[bad, "score_home"] = 0
        grid.loc[bad, "score_away"] = 0
        grid.loc[bad, "period"] = 1
    grid["score_home"] = grid["score_home"].astype(int)
    grid["score_away"] = grid["score_away"].astype(int)
    grid["period"] = grid["period"].astype(int)
    grid["score_margin"] = grid["score_home"] - grid["score_away"]
    grid["time_minute"] = pd.to_datetime(
        grid["time_minute"], utc=True,
    ).astype("datetime64[ns, UTC]")

    sm = smoothed_g[["time_actual", "home_prob_smooth"]].sort_values("time_actual")
    sm = sm.rename(columns={"home_prob_smooth": "p_market_smooth"})
    sm["time_actual"] = sm["time_actual"].astype("datetime64[ns, UTC]")
    grid_sorted = grid.sort_values("time_minute").reset_index(drop=True)
    merged = pd.merge_asof(
        grid_sorted, sm,
        left_on="time_minute",
        right_on="time_actual",
        direction="backward",
    ).drop(columns=["time_actual"])
    merged = merged.sort_values("minute").reset_index(drop=True)
    merged["p_market_smooth"] = merged["p_market_smooth"].ffill()
    return merged


# ---------------------------------------------------------------------------
# Pre-game line extraction (per game).
# ---------------------------------------------------------------------------


def per_game_pregame_line(state: pd.DataFrame) -> float:
    """Pre-game home win prob = mean smoothed home_prob in the first
    PRE_GAME_LINE_SECS of the per-minute state."""
    if state.empty:
        return float("nan")
    n_minutes_window = max(1, PRE_GAME_LINE_SECS // MINUTE_BAR_SECONDS)
    head = state.head(n_minutes_window)
    val = head["p_market_smooth"].dropna()
    if val.empty:
        val = state["p_market_smooth"].dropna()
        if val.empty:
            return float("nan")
        return float(val.iloc[0])
    return float(val.mean())


def per_game_sigma_hat(state: pd.DataFrame) -> float:
    """Per-game empirical sigma = std of one-minute score-margin diffs."""
    if state.empty or len(state) < 2:
        return float("nan")
    diffs = state["score_margin"].diff().dropna().to_numpy(dtype=float)
    if diffs.size < 2:
        return float("nan")
    return float(np.std(diffs, ddof=1))


# ---------------------------------------------------------------------------
# Polson-Stern model (per-fold).
# ---------------------------------------------------------------------------


def calibrate_sigma_global(
    state_by_game: dict[str, pd.DataFrame], train_ids: Iterable[str],
) -> tuple[float, int]:
    """Median per-game sigma_hat over training games. Returns (sigma, n)."""
    sigmas: list[float] = []
    train_set = set(train_ids)
    for gid, state in state_by_game.items():
        if gid not in train_set:
            continue
        s = per_game_sigma_hat(state)
        if np.isfinite(s):
            sigmas.append(s)
    if not sigmas:
        return float("nan"), 0
    return float(np.median(np.asarray(sigmas, dtype=float))), len(sigmas)


def calibrate_mu_per_game(p_pregame: float, sigma_global: float) -> float:
    """mu = Phi^-1(p_pregame) * sigma_global * sqrt(T) / T (consistent
    calibration: minute-0 p_hat = pregame line by construction)."""
    if not np.isfinite(p_pregame) or p_pregame <= 0.0 or p_pregame >= 1.0:
        return float("nan")
    if not np.isfinite(sigma_global) or sigma_global <= 0:
        return float("nan")
    return float(
        norm.ppf(p_pregame) * sigma_global * np.sqrt(T_TOTAL_MIN) / T_TOTAL_MIN,
    )


def compute_p_hat_series(
    *,
    score_margin: np.ndarray,
    minute: np.ndarray,
    mu_game: float,
    sigma_global: float,
) -> np.ndarray:
    """p_hat(t) = Phi((M(t) + mu*(T-t)) / (sigma * sqrt(T-t)))."""
    t = minute.astype(float)
    m = score_margin.astype(float)
    rem = T_TOTAL_MIN - t
    valid = rem > 1e-9
    out = np.full_like(t, np.nan, dtype=float)
    if not np.any(valid):
        return out
    rem_valid = rem[valid]
    m_valid = m[valid]
    if not (np.isfinite(mu_game) and np.isfinite(sigma_global) and sigma_global > 0):
        return out
    z = (m_valid + mu_game * rem_valid) / (sigma_global * np.sqrt(rem_valid))
    out[valid] = norm.cdf(z)
    return out


